jQuery.Class("Settings_Users_Auth_Js",{},{registerChangeVal:function(e){e.find(".configField").change(function(e){var t=$(e.currentTarget),s={};s.type=t.data("type"),s.param=t.attr("name"),"checkbox"==t.attr("type")?s.val=this.checked:s.val=t.val(),app.saveAjax("updateConfig",s).then(function(e){Settings_Vtiger_Index_Js.showMessage({type:"success",text:e.result.message})})})},registerEvents:function(){var e=$(".usersAuth");this.registerChangeVal(e)}});